ALTER TABLE tests_for_success ADD COLUMN IF NOT EXISTS status TEXT;                                 -- red | green | planned.
COMMENT ON TABLE tests_for_success IS 'Falsifiable conditions that prove the axioms hold. The human-readable index of what each demonstration shows; many are realized in the witnessed harness.';
COMMENT ON COLUMN tests_for_success.test_for_success_id IS 'Stable identifier.';
COMMENT ON COLUMN tests_for_success.claim IS 'The success condition, stated falsifiably.';
COMMENT ON COLUMN tests_for_success.how_witnessed IS 'How a human/expert confirms it without trusting the code.';
