COMMENT ON COLUMN tests_for_success.status IS 'red | green | planned.';

-- ----------------------------------------------------------------------------
-- Features: Catalog of buildable capabilities the platform has / allows for. Coarser grain than loops. Each row carries challenge provenance (ChallengeRefs: exact quoted text + file/line/col into THE-ORIGINAL-CHALLENGE.md, for UI hover tips), a Category, a Priority, and a free-form Markdown ChallengeNotes comment. Source of truth for the DERIVED PLATFORM_FEATURES.md. AssignedLoop links a feature to the loop that delivers it (nullable until scheduled).
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS features (
  feature_id                          TEXT                 PRIMARY KEY          -- Stable identifier.
);
ALTER TABLE features ADD COLUMN IF NOT EXISTS title TEXT;                                           -- Short feature name.
ALTER TABLE features ADD COLUMN IF NOT EXISTS category TEXT;                                        -- Which layer of the platform this belongs to (Keystone / inference DAG, Leaf / LLM surface, Witness / harness, Disease-state simulation, Treatment reasoning, Corpus-level discovery, Reporting, Platform infrastructure).
ALTER TABLE features ADD COLUMN IF NOT EXISTS priority TEXT;                                        -- Load-bearing | Supporting | Roadmap.
ALTER TABLE features ADD COLUMN IF NOT EXISTS description TEXT;                                     -- What the capability does (factual, not a pitch).
ALTER TABLE features ADD COLUMN IF NOT EXISTS challenge_refs TEXT;                                  -- JSON array of provenance pointers into THE-ORIGINAL-CHALLENGE.md. Each: {file,line,col,len,quote,section,relation}. col is the 0-based char offset within the line; len is the quote length; section is prompt|payoff|audit|response; relation is direct|indirect. Drives UI hover tips that highlight the exact span.
ALTER TABLE features ADD COLUMN IF NOT EXISTS challenge_refs_rendered TEXT;                         -- Pre-flattened Markdown bullet list of ChallengeRefs, so the dumb hbars template can print it verbatim (the engine has no loop-over-JSON helper).
ALTER TABLE features ADD COLUMN IF NOT EXISTS challenge_notes TEXT;                                 -- Free-form Markdown comment: which challenge elements this relates to (directly or indirectly) and how it is load-bearing or illustrative.
ALTER TABLE features ADD COLUMN IF NOT EXISTS ref_count NUMERIC;                                    -- Number of challenge refs (carried as raw for display; the hbars engine can't count a JSON string).
ALTER TABLE features ADD COLUMN IF NOT EXISTS assigned_loop TEXT;                                   -- FK -> LeopoldLoops.LeopoldLoopId; empty if unscheduled.
COMMENT ON TABLE features IS 'Catalog of buildable capabilities the platform has / allows for. Coarser grain than loops. Each row carries challenge provenance (ChallengeRefs: exact quoted text + file/line/col into THE-ORIGINAL-CHALLENGE.md, for UI hover tips), a Category, a Priority, and a free-form Markdown ChallengeNotes comment. Source of truth for the DERIVED PLATFORM_FEATURES.md. AssignedLoop links a feature to the loop that delivers it (nullable until scheduled).';
COMMENT ON COLUMN features.feature_id IS 'Stable identifier.';
COMMENT ON COLUMN features.title IS 'Short feature name.';
COMMENT ON COLUMN features.category IS 'Which layer of the platform this belongs to (Keystone / inference DAG, Leaf / LLM surface, Witness / harness, Disease-state simulation, Treatment reasoning, Corpus-level discovery, Reporting, Platform infrastructure).';
COMMENT ON COLUMN features.priority IS 'Load-bearing | Supporting | Roadmap.';
COMMENT ON COLUMN features.description IS 'What the capability does (factual, not a pitch).';
COMMENT ON COLUMN features.challenge_refs IS 'JSON array of provenance pointers into THE-ORIGINAL-CHALLENGE.md. Each: {file,line,col,len,quote,section,relation}. col is the 0-based char offset within the line; len is the quote length; section is prompt|payoff|audit|response; relation is direct|indirect. Drives UI hover tips that highlight the exact span.';
COMMENT ON COLUMN features.challenge_refs_rendered IS 'Pre-flattened Markdown bullet list of ChallengeRefs, so the dumb hbars template can print it verbatim (the engine has no loop-over-JSON helper).';
COMMENT ON COLUMN features.challenge_notes IS 'Free-form Markdown comment: which challenge elements this relates to (directly or indirectly) and how it is load-bearing or illustrative.';
COMMENT ON COLUMN features.ref_count IS 'Number of challenge refs (carried as raw for display; the hbars engine can''t count a JSON string).';
COMMENT ON COLUMN features.assigned_loop IS 'FK -> LeopoldLoops.LeopoldLoopId; empty if unscheduled.';

-- ----------------------------------------------------------------------------
-- InferenceKinds: Families of derivation the platform performs - the KINDS of inference in the DAG (lookups, aggregations, higher-order gates, state machines, transitive closure, predicate-gated narrative, cross-substrate conformance), independent of any one feature. Lets PLATFORM_FEATURES.md open with a short overview of the reasoning machinery before the per-feature catalog. Grounded in field types that actually exist in this rulebook; Maturity is Live unless an upstream step is still in flight.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS inference_kinds (
  inference_kind_id                   TEXT                 PRIMARY KEY          -- Stable identifier.
);
ALTER TABLE inference_kinds ADD COLUMN IF NOT EXISTS title TEXT;                                    -- Short name of the inference family.
ALTER TABLE inference_kinds ADD COLUMN IF NOT EXISTS description TEXT;                              -- One-line factual description of the kind.
ALTER TABLE inference_kinds ADD COLUMN IF NOT EXISTS example_field TEXT;                            -- A concrete field in the model that realizes this kind.
ALTER TABLE inference_kinds ADD COLUMN IF NOT EXISTS evidence_count TEXT;                           -- How much of it exists (field counts / usage), for honest weight.
ALTER TABLE inference_kinds ADD COLUMN IF NOT EXISTS maturity TEXT;                                 -- Live | Partial (Partial = an upstream step is still in flight).
ALTER TABLE inference_kinds ADD COLUMN IF NOT EXISTS sort_order NUMERIC;                            -- Display order in the overview.
COMMENT ON TABLE inference_kinds IS 'Families of derivation the platform performs - the KINDS of inference in the DAG (lookups, aggregations, higher-order gates, state machines, transitive closure, predicate-gated narrative, cross-substrate conformance), independent of any one feature. Lets PLATFORM_FEATURES.md open with a short overview of the reasoning machinery before the per-feature catalog. Grounded in field types that actually exist in this rulebook; Maturity is Live unless an upstream step is still in flight.';
COMMENT ON COLUMN inference_kinds.inference_kind_id IS 'Stable identifier.';
COMMENT ON COLUMN inference_kinds.title IS 'Short name of the inference family.';
COMMENT ON COLUMN inference_kinds.description IS 'One-line factual description of the kind.';
COMMENT ON COLUMN inference_kinds.example_field IS 'A concrete field in the model that realizes this kind.';
COMMENT ON COLUMN inference_kinds.evidence_count IS 'How much of it exists (field counts / usage), for honest weight.';
COMMENT ON COLUMN inference_kinds.maturity IS 'Live | Partial (Partial = an upstream step is still in flight).';
COMMENT ON COLUMN inference_kinds.sort_order IS 'Display order in the overview.';

-- ----------------------------------------------------------------------------
-- OpenQuestions: Decisions still pending, captured so they are not silently re-litigated in a later session.
