ALTER TABLE open_questions ADD COLUMN IF NOT EXISTS resolution TEXT;                                -- The decision, once made.
ALTER TABLE open_questions ADD COLUMN IF NOT EXISTS is_resolved BOOLEAN;                            -- TRUE when decided.
COMMENT ON TABLE open_questions IS 'Decisions still pending, captured so they are not silently re-litigated in a later session.';
