CREATE TABLE IF NOT EXISTS non_goals (
  non_goal_id                         TEXT                 PRIMARY KEY          -- Stable identifier.
);
ALTER TABLE non_goals ADD COLUMN IF NOT EXISTS statement TEXT;                                      -- What we are deliberately NOT doing.
ALTER TABLE non_goals ADD COLUMN IF NOT EXISTS why_excluded TEXT;                                   -- Why it is off the keystone path / out of scope.
COMMENT ON TABLE non_goals IS 'Explicit out-of-scope statements — the positive twin of the anti-hallucination ledger. Stops scope creep.';
