-- ----------------------------------------------------------------------------
-- LeopoldLoops: The ordered Leopold loops that build this platform, as data. The derived plan (LEOPOLD_LOOPs.md, via json-hbars-transform) is generated from these rows; completed ([DONE]) loops are pruned at publish so only current/roadmap work shows in the plan.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS leopold_loops (
  leopold_loop_id                     TEXT                 PRIMARY KEY          -- Stable identifier.
);
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS loop_number TEXT;                                -- Display number (0, 0.5, 1...).
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS title TEXT;                                      -- Loop title.
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS goal TEXT;                                       -- The one coherent rule-change / outcome.
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS status TEXT;                                     -- done | next | planned | backlog (the raw input that drives Completedness).
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS rule_commit_msg TEXT;                            -- The rule commit message (or "none — app-only loop").
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS state_commit_msg TEXT;                           -- The state commit message.
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS sort_order NUMERIC;                              -- Ordering within the plan.
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS status_badge TEXT;                               -- Display badge for the derived plan, e.g. [DONE] / [NEXT] / [PLANNED] / [BACKLOG].
ALTER TABLE leopold_loops ADD COLUMN IF NOT EXISTS status_line TEXT;                                -- Extra plan line: commit messages for done/next loops; empty otherwise.
COMMENT ON TABLE leopold_loops IS 'The ordered Leopold loops that build this platform, as data. The derived plan (LEOPOLD_LOOPs.md, via json-hbars-transform) is generated from these rows; completed ([DONE]) loops are pruned at publish so only current/roadmap work shows in the plan.';
COMMENT ON COLUMN leopold_loops.leopold_loop_id IS 'Stable identifier.';
COMMENT ON COLUMN leopold_loops.loop_number IS 'Display number (0, 0.5, 1...).';
COMMENT ON COLUMN leopold_loops.title IS 'Loop title.';
COMMENT ON COLUMN leopold_loops.goal IS 'The one coherent rule-change / outcome.';
COMMENT ON COLUMN leopold_loops.status IS 'done | next | planned | backlog (the raw input that drives Completedness).';
COMMENT ON COLUMN leopold_loops.rule_commit_msg IS 'The rule commit message (or "none — app-only loop").';
COMMENT ON COLUMN leopold_loops.state_commit_msg IS 'The state commit message.';
COMMENT ON COLUMN leopold_loops.sort_order IS 'Ordering within the plan.';
COMMENT ON COLUMN leopold_loops.status_badge IS 'Display badge for the derived plan, e.g. [DONE] / [NEXT] / [PLANNED] / [BACKLOG].';
COMMENT ON COLUMN leopold_loops.status_line IS 'Extra plan line: commit messages for done/next loops; empty otherwise.';

-- ----------------------------------------------------------------------------
-- RoutingAndNavigation: Role-based navigation: open-ended parent->child->leaf routes with computed paths. Each route has a template (/intake/case/:caseId); entities carry RelativePath that substitutes their own id/slug. Roles: admin, intake-clinician, diagnosing-doctor, external-llm.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS routing_and_navigation (
  routing_and_navigation_id           TEXT                 PRIMARY KEY          -- Slug PK for this nav node, e.g. nav-intake-case.
);
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS display_name TEXT;                      -- Human-readable nav label.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS route TEXT;                             -- URL template, role/workflow-prefixed with :params, e.g. /intake/case/:caseId.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS description TEXT;                       -- What this route shows.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS sort_order NUMERIC;                     -- Display order within its nav level.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS parent_route_key TEXT;                  -- RouteKey of the parent nav node (empty for top-level). Self-referential recursion.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS route_key TEXT;                         -- Stable dot-delimited slug, e.g. diagnosis.case.mechanism.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS nav_level TEXT;                         -- Hierarchy level: top / sub / leaf.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS role_visibility TEXT;                   -- CSV of roles that can see this nav item: admin,intake-clinician,diagnosing-doctor,external-llm.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS primary_table TEXT;                     -- Backing table name.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS primary_view TEXT;                      -- Backing vw_* view.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS icon_hint TEXT;                         -- Optional icon name for the UI.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS is_dynamic BOOLEAN;                     -- True if the route template contains :params.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS pin_to_top BOOLEAN;                     -- Pin to the top of its nav level, before SortOrder.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS admin_crud TEXT;                        -- Admin CRUD grant for this route (contains C/R/U/D). Empty = no access.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS intake_clinician_crud TEXT;             -- IntakeClinician CRUD grant for this route (contains C/R/U/D). Empty = no access.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS diagnosing_doctor_crud TEXT;            -- DiagnosingDoctor CRUD grant for this route (contains C/R/U/D). Empty = no access.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS external_llm_crud TEXT;                 -- ExternalLlm CRUD grant for this route (contains C/R/U/D). Empty = no access.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ;                 -- Audit: when first inserted.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS created_by TEXT;                        -- Audit: owner who created it.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS modified_at TIMESTAMPTZ;                -- Audit: when last written.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS modified_by TEXT;                       -- Audit: who last wrote it.
ALTER TABLE routing_and_navigation ADD COLUMN IF NOT EXISTS modified_by_model TEXT;                 -- Audit: AI model credited on last save, if any.
COMMENT ON TABLE routing_and_navigation IS 'Role-based navigation: open-ended parent->child->leaf routes with computed paths. Each route has a template (/intake/case/:caseId); entities carry RelativePath that substitutes their own id/slug. Roles: admin, intake-clinician, diagnosing-doctor, external-llm.';
COMMENT ON COLUMN routing_and_navigation.routing_and_navigation_id IS 'Slug PK for this nav node, e.g. nav-intake-case.';
COMMENT ON COLUMN routing_and_navigation.display_name IS 'Human-readable nav label.';
COMMENT ON COLUMN routing_and_navigation.route IS 'URL template, role/workflow-prefixed with :params, e.g. /intake/case/:caseId.';
COMMENT ON COLUMN routing_and_navigation.description IS 'What this route shows.';
COMMENT ON COLUMN routing_and_navigation.sort_order IS 'Display order within its nav level.';
COMMENT ON COLUMN routing_and_navigation.parent_route_key IS 'RouteKey of the parent nav node (empty for top-level). Self-referential recursion.';
COMMENT ON COLUMN routing_and_navigation.route_key IS 'Stable dot-delimited slug, e.g. diagnosis.case.mechanism.';
COMMENT ON COLUMN routing_and_navigation.nav_level IS 'Hierarchy level: top / sub / leaf.';
COMMENT ON COLUMN routing_and_navigation.role_visibility IS 'CSV of roles that can see this nav item: admin,intake-clinician,diagnosing-doctor,external-llm.';
COMMENT ON COLUMN routing_and_navigation.primary_table IS 'Backing table name.';
COMMENT ON COLUMN routing_and_navigation.primary_view IS 'Backing vw_* view.';
COMMENT ON COLUMN routing_and_navigation.icon_hint IS 'Optional icon name for the UI.';
COMMENT ON COLUMN routing_and_navigation.is_dynamic IS 'True if the route template contains :params.';
COMMENT ON COLUMN routing_and_navigation.pin_to_top IS 'Pin to the top of its nav level, before SortOrder.';
COMMENT ON COLUMN routing_and_navigation.admin_crud IS 'Admin CRUD grant for this route (contains C/R/U/D). Empty = no access.';
COMMENT ON COLUMN routing_and_navigation.intake_clinician_crud IS 'IntakeClinician CRUD grant for this route (contains C/R/U/D). Empty = no access.';
COMMENT ON COLUMN routing_and_navigation.diagnosing_doctor_crud IS 'DiagnosingDoctor CRUD grant for this route (contains C/R/U/D). Empty = no access.';
COMMENT ON COLUMN routing_and_navigation.external_llm_crud IS 'ExternalLlm CRUD grant for this route (contains C/R/U/D). Empty = no access.';
COMMENT ON COLUMN routing_and_navigation.created_at IS 'Audit: when first inserted.';
COMMENT ON COLUMN routing_and_navigation.created_by IS 'Audit: owner who created it.';
