-- ----------------------------------------------------------------------------
-- SubjectStateInstances: Per-subject state occupancy records; current state has blank ExitedAt.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS subject_state_instances (
  subject_state_instance_id           TEXT                 PRIMARY KEY          -- PK: ssi-{subject-id}-{state-key}-{seq}.
);
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS state_machine TEXT;                    -- FK -> StateMachines.StateMachineId.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS subject_table_name TEXT;               -- Polymorphic table name.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS subject_id TEXT;                       -- Polymorphic PK of the subject row.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS state_key TEXT;                        -- The machine state entered by this occupancy record.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS entered_at TIMESTAMPTZ;                -- Timestamp when this state was entered.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS exited_at TIMESTAMPTZ;                 -- Timestamp when the subject left this state. NULL while current.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS sequence_index NUMERIC;                -- 1-based position on this subject's path through the machine.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS prior_instance TEXT;                   -- Self-FK: previous occupancy in this subject's chain. NULL for initial.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS entered_via_transition TEXT;           -- FK -> StateTransitions: the edge event that created this occupancy.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ;                -- Audit: when first inserted.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS created_by TEXT;                       -- Audit: owner who created it.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS modified_at TIMESTAMPTZ;               -- Audit: when last written.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS modified_by TEXT;                      -- Audit: who last wrote it.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS modified_by_model TEXT;                -- Audit: AI model credited on last save, if any.
ALTER TABLE subject_state_instances ADD COLUMN IF NOT EXISTS dwell_days NUMERIC;                    -- Bitemporal dwell: days the subject occupied this state (transparent raw value; transpiler lacks date-diff). Witnessed + editable, like any leaf.
COMMENT ON TABLE subject_state_instances IS 'Per-subject state occupancy records; current state has blank ExitedAt.';
COMMENT ON COLUMN subject_state_instances.subject_state_instance_id IS 'PK: ssi-{subject-id}-{state-key}-{seq}.';
COMMENT ON COLUMN subject_state_instances.state_machine IS 'FK -> StateMachines.StateMachineId.';
COMMENT ON COLUMN subject_state_instances.subject_table_name IS 'Polymorphic table name.';
COMMENT ON COLUMN subject_state_instances.subject_id IS 'Polymorphic PK of the subject row.';
COMMENT ON COLUMN subject_state_instances.state_key IS 'The machine state entered by this occupancy record.';
COMMENT ON COLUMN subject_state_instances.entered_at IS 'Timestamp when this state was entered.';
COMMENT ON COLUMN subject_state_instances.exited_at IS 'Timestamp when the subject left this state. NULL while current.';
COMMENT ON COLUMN subject_state_instances.sequence_index IS '1-based position on this subject''s path through the machine.';
COMMENT ON COLUMN subject_state_instances.prior_instance IS 'Self-FK: previous occupancy in this subject''s chain. NULL for initial.';
COMMENT ON COLUMN subject_state_instances.entered_via_transition IS 'FK -> StateTransitions: the edge event that created this occupancy.';
COMMENT ON COLUMN subject_state_instances.created_at IS 'Audit: when first inserted.';
COMMENT ON COLUMN subject_state_instances.created_by IS 'Audit: owner who created it.';
COMMENT ON COLUMN subject_state_instances.modified_at IS 'Audit: when last written.';
COMMENT ON COLUMN subject_state_instances.modified_by IS 'Audit: who last wrote it.';
COMMENT ON COLUMN subject_state_instances.modified_by_model IS 'Audit: AI model credited on last save, if any.';
COMMENT ON COLUMN subject_state_instances.dwell_days IS 'Bitemporal dwell: days the subject occupied this state (transparent raw value; transpiler lacks date-diff). Witnessed + editable, like any leaf.';

-- ----------------------------------------------------------------------------
-- DiseaseDomainConcepts: v2 vocabulary completeness: every disease-domain concept the v1 audit named, with its modeling status and the challenge-stressor TYPE it instantiates. Makes the coverage claim checkable by grep, not by trust.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS disease_domain_concepts (
  disease_domain_concept_id           TEXT                 PRIMARY KEY          -- Slug PK.
);
ALTER TABLE disease_domain_concepts ADD COLUMN IF NOT EXISTS concept_label TEXT;                    -- Human-readable concept name (the audit's missing word).
ALTER TABLE disease_domain_concepts ADD COLUMN IF NOT EXISTS related_disease TEXT;                  -- Disease this concept belongs to (SLE/RA/PsA/* for cross-cutting). Convention string, not a FK.
ALTER TABLE disease_domain_concepts ADD COLUMN IF NOT EXISTS modeling_status TEXT;                  -- deep-dag | schema | vocabulary — how deeply v2 models this concept.
ALTER TABLE disease_domain_concepts ADD COLUMN IF NOT EXISTS definition TEXT;                       -- What the concept is and how v2 represents it.
ALTER TABLE disease_domain_concepts ADD COLUMN IF NOT EXISTS challenge_stressor_type TEXT;          -- Which TYPE of original-challenge stressor this concept instantiates (for the reconcile map).
COMMENT ON TABLE disease_domain_concepts IS 'v2 vocabulary completeness: every disease-domain concept the v1 audit named, with its modeling status and the challenge-stressor TYPE it instantiates. Makes the coverage claim checkable by grep, not by trust.';
COMMENT ON COLUMN disease_domain_concepts.disease_domain_concept_id IS 'Slug PK.';
COMMENT ON COLUMN disease_domain_concepts.concept_label IS 'Human-readable concept name (the audit''s missing word).';
COMMENT ON COLUMN disease_domain_concepts.related_disease IS 'Disease this concept belongs to (SLE/RA/PsA/* for cross-cutting). Convention string, not a FK.';
COMMENT ON COLUMN disease_domain_concepts.modeling_status IS 'deep-dag | schema | vocabulary — how deeply v2 models this concept.';
COMMENT ON COLUMN disease_domain_concepts.definition IS 'What the concept is and how v2 represents it.';
COMMENT ON COLUMN disease_domain_concepts.challenge_stressor_type IS 'Which TYPE of original-challenge stressor this concept instantiates (for the reconcile map).';

-- ----------------------------------------------------------------------------
-- SerologyObservations: RAW longitudinal serology panels (the lab/LLM layer) + derived trend, SLEDAI sub-scores, and the disease state IMPLIED by each panel. The leaves that drive the lupus-nephritis progression machine.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS serology_observations (
  serology_observation_id             TEXT                 PRIMARY KEY          -- Slug PK: sero-{ind}-{seq}.
);
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS individual TEXT;                         -- FK -> Individuals.IndividualId.
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS observed_at TIMESTAMPTZ;                 -- Valid-time of this serology panel (RAW leaf).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS sequence_index NUMERIC;                  -- 1-based order within the individual's panel series (RAW).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS anti_ds_dna_iu NUMERIC;                  -- anti-dsDNA titre IU/mL (RAW lab).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS complement_c3 NUMERIC;                   -- C3 mg/dL (RAW lab).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS complement_c4 NUMERIC;                   -- C4 mg/dL (RAW lab).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS proteinuria_g_per_day NUMERIC;           -- urine protein g/day (RAW lab).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS egfr_ml_min NUMERIC;                     -- eGFR mL/min (RAW lab).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS has_active_urinary_sediment BOOLEAN;     -- active casts/hematuria (RAW observation).
ALTER TABLE serology_observations ADD COLUMN IF NOT EXISTS prior_observation TEXT;                  -- Self-FK -> the prior panel in this individual's series (seq-1). NULL for the first.
COMMENT ON TABLE serology_observations IS 'RAW longitudinal serology panels (the lab/LLM layer) + derived trend, SLEDAI sub-scores, and the disease state IMPLIED by each panel. The leaves that drive the lupus-nephritis progression machine.';
COMMENT ON COLUMN serology_observations.serology_observation_id IS 'Slug PK: sero-{ind}-{seq}.';
COMMENT ON COLUMN serology_observations.individual IS 'FK -> Individuals.IndividualId.';
COMMENT ON COLUMN serology_observations.observed_at IS 'Valid-time of this serology panel (RAW leaf).';
COMMENT ON COLUMN serology_observations.sequence_index IS '1-based order within the individual''s panel series (RAW).';
COMMENT ON COLUMN serology_observations.anti_ds_dna_iu IS 'anti-dsDNA titre IU/mL (RAW lab).';
COMMENT ON COLUMN serology_observations.complement_c3 IS 'C3 mg/dL (RAW lab).';
COMMENT ON COLUMN serology_observations.complement_c4 IS 'C4 mg/dL (RAW lab).';
COMMENT ON COLUMN serology_observations.proteinuria_g_per_day IS 'urine protein g/day (RAW lab).';
COMMENT ON COLUMN serology_observations.egfr_ml_min IS 'eGFR mL/min (RAW lab).';
COMMENT ON COLUMN serology_observations.has_active_urinary_sediment IS 'active casts/hematuria (RAW observation).';
COMMENT ON COLUMN serology_observations.prior_observation IS 'Self-FK -> the prior panel in this individual''s series (seq-1). NULL for the first.';

-- ----------------------------------------------------------------------------
-- TherapyOptions: Therapy lookup for the treatment-line-selection DAG (MMF/belimumab/anifrolumab/secukinumab).
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS therapy_options (
  therapy_option_id                   TEXT                 PRIMARY KEY          -- Slug PK.
);
ALTER TABLE therapy_options ADD COLUMN IF NOT EXISTS therapy_label TEXT;                            -- Therapy name.
ALTER TABLE therapy_options ADD COLUMN IF NOT EXISTS targets_pathway TEXT;                          -- Pathway this therapy targets (matches CausalMechanisms.TargetPathway).
ALTER TABLE therapy_options ADD COLUMN IF NOT EXISTS line_ordinal NUMERIC;                          -- Treatment-line ordinal (1=first-line/induction).
ALTER TABLE therapy_options ADD COLUMN IF NOT EXISTS preferred_when TEXT;                           -- Clinical context where preferred.
COMMENT ON TABLE therapy_options IS 'Therapy lookup for the treatment-line-selection DAG (MMF/belimumab/anifrolumab/secukinumab).';
COMMENT ON COLUMN therapy_options.therapy_option_id IS 'Slug PK.';
COMMENT ON COLUMN therapy_options.therapy_label IS 'Therapy name.';
COMMENT ON COLUMN therapy_options.targets_pathway IS 'Pathway this therapy targets (matches CausalMechanisms.TargetPathway).';
COMMENT ON COLUMN therapy_options.line_ordinal IS 'Treatment-line ordinal (1=first-line/induction).';
COMMENT ON COLUMN therapy_options.preferred_when IS 'Clinical context where preferred.';

